const PROJ = { lonMin: 16.83380126953125, latMax: 49.61375049597579, kx: 0.6603576839964802, scale: 264.2454113398882 };

export function project(lat: number, lon: number): { x: number; y: number } {
  return {
    x: (lon - PROJ.lonMin) * PROJ.kx * PROJ.scale,
    y: (PROJ.latMax - lat) * PROJ.scale,
  };
}
